import argparse
import sys

from azvision import VisionFeatures, scan


def create_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="azscan",
        description="Azure Computer Vision endpoint from the command line.",
    )

    parser.add_argument("image", help="URL or path to an image to scan.")
    parser.add_argument(
        "-E",
        "--env",
        help="Path to .env file that contains VISION_KEY and VISION_ENDPOINT.",
    )
    parser.add_argument(
        "-k",
        "--key",
        help="VISION_KEY to use with the request"
        "use with --endpoint instead of --env.",
    )
    parser.add_argument(
        "-e",
        "--endpoint",
        help="VISION_ENDPOINT to use for the request,"
        "use with --key instead of --env.",
    )
    parser.add_argument(
        "-l",
        "--language",
        default="en",
        help="Set langauge of the vision request.",
    )
    parser.add_argument(
        "-f",
        "--feature",
        choices=[e.value for e in VisionFeatures],
        default=[VisionFeatures.READ.value],
        nargs="+",
        help="Choose feature(s) of the vision request.",
    )
    parser.add_argument(
        "-o",
        "--output",
        choices=["json", "str"],
        default="str",
        help="Choose how to output the vision response",
    )
    return parser


def main() -> None:
    parser = create_parser()
    args = parser.parse_args()

    resp = scan(
        args.image,
        key=args.key,
        endpoint=args.endpoint,
        env_file=args.env,
        features=args.feature,
        language=args.language,
    )

    if args.output == "str":
        print(resp.readResult.content)
    elif args.output == "json":
        print(resp.model_dump_json())
    else:
        raise ValueError(f"Unknown output type '{args.output}'")


if __name__ == "__main__":
    sys.exit(main())
